if (!document.getElementById('fleet-font')) {
  const style = document.createElement('style');
  style.id = 'fleet-font';
  style.textContent = "@font-face { font-family: 'GlassTTY'; src: url('/public/fonts/Glass_TTY_VT220.ttf') format('truetype'); }";
  document.head.appendChild(style);
  document.fonts.load('18px GlassTTY').catch(() => {});
}
const FONT = "'GlassTTY', 'Roboto Mono', 'Consolas', monospace";
const FS = 18;
const LINE_H = 21;
const PL = 8;
const PT = 6;

// Blink toggle: flips every second, visible on each 5s data refresh
const _blink = Math.floor(Date.now() / 1000) % 2 === 0;

const _mc = document.createElement('canvas').getContext('2d');
_mc.font = FS + 'px ' + FONT;
const CW = _mc.measureText('M').width;

// Helpers
function simpleHash(str) {
  let h0=0x811c9dc5,h1=0x01000193,h2=0xdeadbeef;
  for(let i=0;i<str.length;i++){const c=str.charCodeAt(i);h0=((h0^c)*0x01000193)>>>0;h1=((h1^c)*0x811c9dc5)>>>0;h2=((h2^c)*0x1b873593)>>>0;}
  return[(h0>>>24)&0xff,(h1>>>24)&0xff,(h2>>>24)&0xff];
}
function entityColor(n,s){
  const b=simpleHash((s||'')+(n||''));
  let ch=[60+(b[0]*150/255),60+(b[1]*150/255),60+(b[2]*150/255)];
  let mx=0,mn=0;for(let i=1;i<3;i++){if(ch[i]>ch[mx])mx=i;if(ch[i]<ch[mn])mn=i;}
  ch[mx]=Math.min(ch[mx]+40,230);ch[mn]=Math.max(ch[mn]-30,40);
  return ch.map(Math.round);
}
function rgbS(c){return'rgb('+c[0]+','+c[1]+','+c[2]+')';}
function trunc(s,w){s=s||'';if(s.length<=w)return s;return w>2?s.substring(0,w-1)+'~':s.substring(0,w);}
function humanTok(n){if(!n)return'0';if(n>=1e6)return(n/1e6).toFixed(1)+'M';if(n>=1e3)return(n/1e3).toFixed(0)+'k';return''+n;}
function fmtCost(c){if(!c)return'$0';if(c<.5)return'<$1';return'$'+Math.round(c);}
function modelAbbrev(m){if(!m)return'--';let b=m;const i=b.indexOf('[1m]');if(i>=0)b=b.substring(0,i);b=b.replace(/^claude-/,'');return b.length>10?b.substring(0,9)+'~':b;}
function relTime(ts){if(!ts)return'—';const d=new Date(ts);if(isNaN(d))return'—';const s=Math.floor((Date.now()-d)/1000);if(s<60)return s+'s';if(s<3600)return Math.floor(s/60)+'m';if(s<86400)return Math.floor(s/3600)+'h';return Math.floor(s/86400)+'d';}
function sp8(s){return(s||'').substring(0,8);}
function dispName(an){return an===''?'@lead':(an.startsWith('@')?an:'@'+an);}

const CTX_A=[{p:0,c:[63,185,80]},{p:.45,c:[227,179,65]},{p:.7,c:[240,136,62]},{p:.9,c:[248,81,73]}];
function ctxG(f){if(f<=CTX_A[0].p)return CTX_A[0].c;const L=CTX_A[CTX_A.length-1];if(f>=L.p)return L.c;for(let i=1;i<CTX_A.length;i++){const lo=CTX_A[i-1],hi=CTX_A[i];if(f>hi.p)continue;const t=(f-lo.p)/(hi.p-lo.p);return[Math.round(lo.c[0]+t*(hi.c[0]-lo.c[0])),Math.round(lo.c[1]+t*(hi.c[1]-lo.c[1])),Math.round(lo.c[2]+t*(hi.c[2]-lo.c[2]))];}return L.c;}
function costG(c,mx){if(c<=0||mx<=0)return[31,92,40];const t=Math.min(Math.max(Math.log(c+1)/Math.log(mx+1),0),1);return[Math.round(31+t*79),Math.round(92+t*163),Math.round(40+t*90)];}
function hDotC(l){if(l==='critical')return[248,81,73];if(l==='warning')return[227,179,65];return[63,185,80];}

function buildTree(rows){
  const bR={};rows.forEach((r,i)=>{if(r.rosterID)bR[r.rosterID]=i;});
  const ch={},orph={},roots=[];
  rows.forEach((r,i)=>{const pi=r.parentRef?bR[r.parentRef]:undefined;const wn=r.relationship==='subagent'||(pi!==undefined);if(!wn)roots.push(i);else if(pi===undefined){orph[i]=true;roots.push(i);}else{if(!ch[pi])ch[pi]=[];ch[pi].push(i);}});
  const res=[],em={};
  function walk(i,cont){if(em[i])return;em[i]=true;let pfx='';if(orph[i])pfx='↳';else if(cont.length>0){let p='';for(let k=0;k<cont.length-1;k++)p+=cont[k]?'│ ':'  ';p+=(cont[cont.length-1]?'├':'└')+(rows[i].relationship==='subagent'?'─':'');pfx=p;}res.push({agent:rows[i],prefix:pfx});const kids=ch[i]||[];for(let k=0;k<kids.length;k++)walk(kids[k],cont.concat([k<kids.length-1]));}
  for(const i of roots)walk(i,[]);for(let i=0;i<rows.length;i++){if(!em[i]){orph[i]=true;walk(i,[]);}}return res;
}

// Activity helpers
const TAG_C={'GOAL':[255,200,60],'THNK':[140,170,130],'DONE':[0,102,0],'READ':[0,0,255],'EDIT':[128,128,0],'GREP':[120,140,200],'ACT':[230,150,50],'EXEC':[180,160,60],'TEAM':[180,120,220],'COMM':[150,140,210],'TASK':[240,110,170],'WEB':[210,130,180],'ASK':[255,100,100],'PLAN':[160,160,220],'TOOL':[160,160,160],'WARN':[255,160,40]};
function renderDisplay(display, tagColorStr, pfx) {
  const line = (display||'').replace(/\r?\n/g,' ').replace(/[\r\x00-\x1f]/g,'');
  const parts = line.split(/__([^_]+)__/g);
  const rich = {}; let text = '';
  for (let j = 0; j < parts.length; j++) {
    let part = parts[j]; const key = pfx + '_' + j;
    if (j % 2 === 1) {
      if (j > 0 && parts[j-1].endsWith(' ')) part = ' ' + part;
      rich[key] = { fontFamily: FONT, fontSize: FS, fill: 'rgb(0,255,255)' };
    } else {
      if (j < parts.length - 1 && part.endsWith(' ')) part = part.slice(0, -1);
      rich[key] = { fontFamily: FONT, fontSize: FS, fill: tagColorStr };
    }
    text += '{' + key + '|' + part + '}';
  }
  return { text, rich };
}
function tagC(t){return TAG_C[(t||'').trim()]||TAG_C['TOOL'];}
function padTag(t){t=(t||'').trim();return t.length>=4?t.substring(0,4):' '.repeat(4-t.length)+t;}

function fieldFrom(series,name){if(!series||!series.fields)return[];const f=series.fields.find(x=>x.name===name);if(!f)return[];return f.values.buffer||f.values;}

// ═══════ DATA ═══════
const allS = context.panel.data.series || [];
const els = [];
let row = 0;
function addCell(colChars, y, text, fill, opts) {
  const o = opts || {};
  const s = { text: text, fill: fill, fontFamily: FONT, fontSize: FS };
  if (o.bold) s.fontWeight = 'bold';
  els.push({ type: 'text', left: PL + colChars * CW, top: y, style: s });
}
function rowY() { return PT + row * LINE_H; }

// ═══════ FLEET GRID ═══════
const agS = allS[0];
// Fixed column widths (same as ctop)
const DOT_W = 2, AGE_W = 4, CTX_W = 4, BAR_W = 12, COST_W = 5, TOK_W = 5;

if (agS && agS.fields && agS.fields.length > 0) {
  const f=(n)=>fieldFrom(agS,n);
  const sA=f('session_id'),nA=f('agent_name'),rtA=f('runtime'),mdA=f('model'),tnA=f('team_name');
  const rlA=f('relationship'),prA=f('parent_ref'),riA=f('roster_id'),lvA=f('liveness');
  const cfA=f('context_fill_pct'),csA=f('session_cost_usd'),tcA=f('session_total_cost_usd');
  const plA=f('pressure_level'),clA=f('collector_status');
  const tiA=f('tokens_in_total'),toA=f('tokens_out_total');
  const ltA=f('last_activity_ts'),ldA=f('last_activity_display'),laA=f('last_activity_tag');
  const fcA=f('current_focus'),hsA=f('host'),usA=f('username');

  const agents=[];
  for(let i=0;i<(sA.length||0);i++){
    agents.push({sid:sA[i]||'',an:nA[i]||'',rt:rtA[i]||'',md:mdA[i]||'',tn:tnA[i]||'',
      rel:rlA[i]||'',pr:prA[i]||'',rid:riA[i]||'',lv:lvA[i]||'',cf:cfA[i]||0,
      cs:csA[i]||0,tc:tcA[i]||0,pl:plA[i]||'',cl:clA[i]||'',
      ti:tiA[i]||0,to:toA[i]||0,lt:ltA[i]||'',ld:ldA[i]||'',la:laA[i]||'',
      fc:fcA[i]||'',hs:hsA[i]||'',us:usA[i]||'',
      rosterID:riA[i]||'',parentRef:prA[i]||'',relationship:rlA[i]||''});
  }

  const cut=Date.now()-3600000;
  const fresh=agents.filter(a=>{
    if(a.an==='@')return false;
    if(!a.lt&&!a.ld)return false; // no activity ever — phantom roster entry
    if(a.lv==='live'||a.lv==='idle')return true;
    if(!a.lt)return false;
    return new Date(a.lt).getTime()>cut;
  });

  const sOrd=[],bySes={};
  for(const a of fresh){if(!bySes[a.sid]){sOrd.push(a.sid);bySes[a.sid]=[];}bySes[a.sid].push(a);}
  function gRec(rows){let l=0;for(const r of rows){if(r.lt){const t=new Date(r.lt).getTime();if(t>l)l=t;}}return l;}
  for(let i=sOrd.length-1;i>=0;i--){if(!bySes[sOrd[i]]||!bySes[sOrd[i]].length)sOrd.splice(i,1);}
  sOrd.sort((a,b)=>gRec(bySes[b])-gRec(bySes[a]));
  for(const sid of sOrd)bySes[sid].sort((a,b)=>(b.rel==='lead'||b.an===''?1:0)-(a.rel==='lead'||a.an===''?1:0));

  // Build all tree rows FIRST to compute dynamic column widths
  const allTreeRows = [];
  for (const sid of sOrd) {
    const gRows = bySes[sid];
    if (!gRows || !gRows.length) continue;
    const tree = buildTree(gRows);
    allTreeRows.push({ sid: sid, rows: tree, agents: gRows });
  }

  // Dynamic MDL_W: widest model abbreviation, floor 5, cap 9
  let MDL_W = 5;
  for (const a of fresh) {
    const w = modelAbbrev(a.md).length;
    if (w > MDL_W) MDL_W = w;
  }
  if (MDL_W > 10) MDL_W = 10;

  // Dynamic AGENT_W: widest prefix+name across all tree rows, default 11, greedy up to 24
  // Grows only when data demands it — connectors (├─ = 3 chars per level) + names need room
  let AGENT_W = 11;
  for (const group of allTreeRows) {
    for (const tr of group.rows) {
      const dn = dispName(tr.agent.an);
      const w = (tr.prefix || '').length + dn.length + 2; // +2 for team connector added later
      if (w > AGENT_W) AGENT_W = w;
    }
  }
  if (AGENT_W > 24) AGENT_W = 24;

  // ACTIVITY width: remainder after all fixed columns
  // Total layout width: estimate from panel container or use 130 columns
  let TOTAL_W = 130;
  try {
    const panelEl = document.querySelector('.panel-content');
    if (panelEl) TOTAL_W = Math.floor(panelEl.clientWidth / CW) - 2;
  } catch(e) {}
  if (TOTAL_W < 80) TOTAL_W = 80;
  if (TOTAL_W > 200) TOTAL_W = 200;

  // Fixed tail: CTX(4+1) + BAR(12+1) + COST(5+1) + IN(5+1) + OUT(5) = 35
  // Fixed head: MDL(dyn+1) + DOT(2) + AGENT(dyn+1) + AGE(4+1) = MDL+AGENT+9
  const FIXED = (MDL_W+1) + DOT_W + (AGENT_W+1) + (AGE_W+1) + 2 /*ACT gap*/ + (CTX_W+1) + (BAR_W+2) /*BAR gap*/ + (COST_W+1) + (TOK_W+1) + TOK_W;
  let ACT_W = TOTAL_W - FIXED;
  if (ACT_W < 20) ACT_W = 20;

  // Compute column positions (in character units)
  let cx = 0;
  const C_MDL = cx; cx += MDL_W + 1;
  const C_DOT = cx; cx += DOT_W;
  const C_AGT = cx; cx += AGENT_W + 1;
  const C_AGE = cx; cx += AGE_W + 1;
  const C_ACT = cx; cx += ACT_W + 2;
  const C_CTX = cx; cx += CTX_W + 1;
  const C_BAR = cx; cx += BAR_W + 2;
  const C_CST = cx; cx += COST_W + 1;
  const C_IN  = cx; cx += TOK_W + 1;
  const C_OUT = cx;

  // Stats
  let actCnt=0,totCnt=fresh.length,totCst=0,totIn=0,totOut=0;
  for(const a of fresh){if(a.lv==='live'||a.lv==='idle')actCnt++;totCst+=a.cs;totIn+=a.ti;totOut+=a.to;}

  // Header band
  const hbR={};
  hbR.f={fontFamily:FONT,fontSize:FS,fill:'#e3b341',fontWeight:'bold'};
  hbR.s={fontFamily:FONT,fontSize:FS,fill:'#c9d1d9'};
  hbR.c={fontFamily:FONT,fontSize:FS,fill:'#79c0ff'};
  els.push({type:'text',left:PL,top:rowY(),style:{text:'{f|fleet}  {s|Agents: '+actCnt+' of '+totCnt+'}  {c|$'+Math.round(totCst)+' total}',rich:hbR}});
  row++;

  // Column headers — each at its computed position
  const dim='#484f58';
  addCell(C_MDL,rowY(),'MDL',dim,{bold:true});
  addCell(C_DOT,rowY(),'◉',dim,{bold:true});
  addCell(C_AGT,rowY(),'AGENT',dim,{bold:true});
  addCell(C_AGE,rowY(),'AGE',dim,{bold:true});
  addCell(C_ACT,rowY(),'ACTIVITY',dim,{bold:true});
  addCell(C_CTX,rowY(),'CTX',dim,{bold:true});
  addCell(C_CST,rowY(),'$',dim,{bold:true});
  addCell(C_IN,rowY(),'IN',dim,{bold:true});
  addCell(C_OUT,rowY(),'OUT',dim,{bold:true});
  row++;

  // Render groups
  for (const group of allTreeRows) {
    const sid = group.sid;
    const gRows = group.agents;
    const lead = gRows[0];
    const mxCst = Math.max(...gRows.map(r => r.cs));
    const tn = lead.tn;
    const label = tn ? '#'+tn : 'solo·'+sp8(sid);
    const cSrc = tn || sid;
    const lc = entityColor(cSrc, '');
    const foc = (lead.fc||'').replace(/\n/g,' ').replace(/\*\*/g,'').substring(0,40);
    const sCst = lead.tc || gRows.reduce((s,r) => s+r.cs, 0);
    const gIn = gRows.reduce((s,r) => s+r.ti, 0);
    const gOut = gRows.reduce((s,r) => s+r.to, 0);

    // Team header — label is free-flow rich text, economics are positioned cells
    const ri='th'+row; const thR={};
    thR['r'+ri]={fontFamily:FONT,fontSize:FS,fill:lead.rt==='codex'?'#79c0ff':'#3fb950'};
    thR['l'+ri]={fontFamily:FONT,fontSize:FS,fill:rgbS(lc),fontWeight:'bold'};
    thR['d'+ri]={fontFamily:FONT,fontSize:FS,fill:'#484f58'};
    thR['f'+ri]={fontFamily:FONT,fontSize:FS,fill:'#e3b341'};
    let hp='';if(lead.us&&lead.hs)hp=' ('+lead.us+'@'+lead.hs+')';else if(lead.hs)hp=' ('+lead.hs+')';
    let tt='{r'+ri+'|'+(lead.rt==='codex'?'▷':'▶')+'} {l'+ri+'|'+label+'}{d'+ri+'|'+hp+' '+sp8(sid)+'}';
    if(foc)tt+=' {f'+ri+'|['+foc+']}';
    const tintC=entityColor(cSrc,'');
    const bg='rgb('+Math.round(tintC[0]/6)+','+Math.round(tintC[1]/6)+','+Math.round(tintC[2]/6)+')';
    els.push({type:'text',left:PL,top:rowY(),style:{text:tt,rich:thR,backgroundColor:bg,width:2000,padding:[1,4,1,0]}});
    // Economics at grid-aligned positions
    const ty=rowY();
    addCell(C_CST,ty,fmtCost(sCst),'#79c0ff',{bold:true});
    addCell(C_IN,ty,humanTok(gIn),'#79c0ff',{bold:true});
    addCell(C_OUT,ty,humanTok(gOut),'#79c0ff',{bold:true});
    row++;

    // Add team-member connectors (ctop's fleetTeamMemberRows):
    // Each top-level member gets ├ or └ under the team header,
    // nested rows get an extra space indent + their tree prefix.
    const tree = group.rows;
    for (let ti = 0; ti < tree.length; ti++) {
      const isTop = tree[ti].prefix === '' || tree[ti].prefix === '↳';
      if (isTop) {
        const isLast = !tree.slice(ti+1).some(t => t.prefix === '' || t.prefix === '↳');
        const conn = isLast ? '└' : '├';
        tree[ti].prefix = tree[ti].prefix === '↳' ? conn + '↳' : conn;
      } else {
        tree[ti].prefix = ' ' + tree[ti].prefix;
      }
    }

    // Agent rows — per-column positioned elements
    for (const tr of tree) {
      const a = tr.agent; const y = rowY();
      addCell(C_MDL, y, trunc(modelAbbrev(a.md), MDL_W), rgbS(entityColor(a.md,'')));

      // Activity state dot — tag-driven, not time-driven:
      //   terminal tag (DONE/COMP): turn ended → steady ◉ in tag color
      //   any other tag: still processing → blink ◉/○ in tag color
      //   >15m since last activity: dim grey ◉
      //   closed/stale: dim grey ○
      const elapsed = a.lt ? Date.now() - new Date(a.lt).getTime() : Infinity;
      const closed = a.lv === 'closed' || a.lv === 'stale';
      const terminal = a.la === 'DONE' || a.la === 'COMP';
      const tc = TAG_C[a.la] || [110,118,129];
      let dotC, dotG;
      if (closed) {
        dotC = '#484f58'; dotG = '○';
      } else if (elapsed > 900000) {
        dotC = '#484f58'; dotG = '◉';
      } else if (terminal) {
        dotC = rgbS(tc); dotG = '◉';
      } else {
        dotC = rgbS(tc);
        dotG = _blink ? '◉' : '○';
      }
      addCell(C_DOT, y, dotG, dotC);

      const dn = dispName(a.an);
      const saltId = a.sid.substring(0, 12);
      addCell(C_AGT, y, trunc((tr.prefix||'')+dn, AGENT_W), rgbS(entityColor(dn, saltId)));

      addCell(C_AGE, y, trunc(relTime(a.lt), AGE_W), '#8b5a2b');

      const actTxt = (a.ld||'').replace(/\n/g,' ').replace(/\*\*/g,'').replace(/__/g,'').substring(0, ACT_W) || '—';
      const actC = TAG_C[a.la] || [110,118,129];
      addCell(C_ACT, y, trunc(actTxt, ACT_W), rgbS(actC));

      const fill = Math.max(0, Math.min(a.cf, 1));
      addCell(C_CTX, y, Math.round(fill*100)+'%', rgbS(ctxG(fill)));

      // CTX bar — single rich-text element at bar column
      const bF = Math.round(fill * BAR_W);
      const bri = 'br'+row; const bR = {}; let bT = '';
      for(let b=0;b<BAR_W;b++){
        const bk=bri+'_'+b;
        if(b<bF){bR[bk]={fontFamily:FONT,fontSize:FS,fill:rgbS(ctxG((b+.5)/BAR_W))};bT+='{'+bk+'|█}';}
        else{bR[bk]={fontFamily:FONT,fontSize:FS,fill:'#30363d'};bT+='{'+bk+'|░}';}
      }
      els.push({type:'text',left:PL+C_BAR*CW,top:y,style:{text:bT,rich:bR}});

      addCell(C_CST, y, trunc(fmtCost(a.cs), COST_W), rgbS(costG(a.cs, mxCst)));
      addCell(C_IN, y, trunc(humanTok(a.ti), TOK_W), '#79c0ff');
      addCell(C_OUT, y, trunc(humanTok(a.to), TOK_W), '#79c0ff');
      row++;
    }
  }

  // TOTAL
  const y = rowY();
  addCell(C_AGT, y, 'TOTAL', '#c9d1d9', {bold:true});
  addCell(C_ACT, y, totCnt+' agents', '#c9d1d9', {bold:true});
  addCell(C_CST, y, fmtCost(totCst), '#79c0ff', {bold:true});
  addCell(C_IN, y, humanTok(totIn), '#79c0ff', {bold:true});
  addCell(C_OUT, y, humanTok(totOut), '#79c0ff', {bold:true});
  row++;
}

if(row===0){els.push({type:'text',left:'center',top:PT,style:{text:'No agents in scope',fill:'#888',fontFamily:FONT,fontSize:16}});row=2;}

// ═══════ ACTIVITY LOG (series[1]) ═══════
row++;
const evS=allS[1];
if(evS&&evS.fields&&evS.fields.length>0){
  const ef=(n)=>fieldFrom(evS,n);
  const eTs=ef('ts'),eSe=ef('session'),eAg=ef('agent_name'),eTg=ef('tag'),eDi=ef('display');
  const eTm=ef('team'),eFc=ef('focus'),eBs=ef('bash_cmd'),eWn=ef('warn_msg');
  const eLen=eTs.length||0;

  els.push({type:'text',left:0,top:rowY(),style:{text:' activity',fill:'#8ab4f8',fontFamily:FONT,fontSize:FS,fontWeight:'bold',backgroundColor:'#0d2137',width:2000,padding:[2,PL,2,PL]}});
  row++;

  let mxSes=8,mxAg=5;
  for(let i=0;i<eLen;i++){
    const tm=(eTm.length>i?eTm[i]:'')||'';const ag=(eAg[i]||'')||'@lead';
    const sl=tm?('#'+tm).length:8;const al=(ag.startsWith('@')?ag:'@'+ag).length;
    if(sl>mxSes)mxSes=Math.min(sl,14);if(al>mxAg)mxAg=Math.min(al,12);
  }

  for(let i=0;i<eLen;i++){
    const ts=eTs[i]||'',ses=eSe[i]||'',ag=eAg[i]||'@lead',tg=(eTg[i]||'').trim();
    const di=eDi[i]||'',tm=(eTm.length>i?eTm[i]:'')||'';
    const fc=(eFc.length>i?eFc[i]:'')||'',bs=(eBs.length>i?eBs[i]:'')||'';
    const wn=(eWn.length>i?eWn[i]:'')||'';
    if(!tg&&!fc&&!bs&&!wn)continue;

    let tp='';try{const d=new Date(ts);tp=d.toLocaleTimeString('en-GB',{hour:'2-digit',minute:'2-digit',second:'2-digit',hour12:false});}catch(e){tp='??:??:??';}
    const sLbl=tm?'#'+tm:(ses.length>8?ses.substring(0,8):ses);
    const sClr=entityColor(sLbl,ses);
    const aLbl=ag.startsWith('@')?ag:'@'+ag;
    const aClr=entityColor(aLbl,ses);
    let tc=tagC(tg),td=tg,ld=di;
    if(wn){td='WARN';ld=wn;tc=TAG_C['WARN'];}
    if(fc&&!tg){td='GOAL';ld=fc;tc=TAG_C['GOAL'];}

    const ri='e'+row;const rch={};
    rch['t'+ri]={fontFamily:FONT,fontSize:FS,fill:'#666'};
    rch['s'+ri]={fontFamily:FONT,fontSize:FS,fill:rgbS(sClr)};
    rch['a'+ri]={fontFamily:FONT,fontSize:FS,fill:rgbS(aClr)};
    rch['g'+ri]={fontFamily:FONT,fontSize:FS,fill:rgbS(tc)};
    const dTxt=(ld||'').replace(/\r?\n/g,' ').replace(/[\r\x00-\x1f]/g,'');
    const dTrunc=dTxt.length>100?dTxt.substring(0,97)+'...':dTxt;
    const disp=renderDisplay(dTrunc,rgbS(tc),'d'+ri);
    Object.assign(rch,disp.rich);
    const lt='{t'+ri+'|'+tp+' }{s'+ri+'|'+sLbl.padEnd(mxSes)+' }{a'+ri+'|'+aLbl.padEnd(mxAg)+' }{g'+ri+'|['+padTag(td)+'] }'+disp.text;
    els.push({type:'text',left:PL,top:rowY(),style:{text:lt,rich:rch}});
    row++;
  }
}

if(!els.length)els.push({type:'text',left:'center',top:'center',style:{text:'No data',fill:'#888',fontFamily:FONT,fontSize:16}});

return {
  backgroundColor: '#181b1f',
  animation: false,
  graphic: [{ type: 'group', $action: 'replace', children: els }],
  series: []
};
